fixes.replacement:
static void destroy_record(Record *r)
{
    if (!r)
        return;

    for (int i = 0; i < 4; i++)
        if (table[i] == r)
            table[i] = NULL;

    if (r->name)
        free(r->name);

    free(r);
}
